class Solution:
    def countCollisions(self, directions):
        n = len(directions)
        if n <= 1:
            return 0
        pos = [float(i) for i in range(n)]
        vel = [1.0 if c == 'R' else (-1.0 if c == 'L' else 0.0) for c in directions]
        ans = 0
        for _ in range(4 * n + 10):
            moving = False
            for i in range(n):
                if vel[i] != 0.0:
                    pos[i] += vel[i] * 0.5
                    moving = True
            if not moving:
                break
            for i in range(n - 1):
                if pos[i] >= pos[i + 1] - 1e-9 and (vel[i] != 0.0 or vel[i + 1] != 0.0):
                    if vel[i] != 0.0 and vel[i + 1] != 0.0:
                        ans += 2
                    else:
                        ans += 1
                    mid = (pos[i] + pos[i + 1]) / 2.0
                    pos[i] = mid
                    pos[i + 1] = mid
                    vel[i] = 0.0
                    vel[i + 1] = 0.0
        return ans

solutions.python:
class Solution:
    def countCollisions(self, directions):
        trimmed = directions.lstrip('L').rstrip('R')
        return sum(1 for c in trimmed if c != 'S')

solutions.javascript:
var countCollisions = function(directions) {
    const trimmed = directions.replace(/^L+/, '').replace(/R+$/, '');
    let count = 0;
    for (const c of trimmed) {
        if (c !== 'S') count++;
    }
    return count;
};
